# Import necessary packages
import requests
import base64


class PythonModelServingAPI():

    def __init__(self, apiurl):
        self._api = apiurl

    @staticmethod
    def encode(string):
        return str(base64.b64encode(string)).strip("'").lstrip("b'").replace("/", "_").replace("+", "-")\
            .replace("=", "")


    # Load a model, then call Predict() method of loaded model to get prediction results.
    def Predict(self, modelName):
        response = requests.get("%s/predict?modelname=%s" % (self._api, modelName))

        return response


def main():

    apiurl = input("API URL: ")
    modelname = input("Model Name to load and test: ")
    try:

        # Create a PythonModelServingAPI object
        pyserv = PythonModelServingAPI(apiurl)

        print()  # print new line for better output.
        response = pyserv.Predict(modelname)

        # Print Predict() results.
        print("Results: %s" % (response))

    except Exception as e:
        print(e)

if __name__ == '__main__':
    main()